 19	function renderHookTest<TResult>(callback: () => TResult) {
 20	  const values: { current: TResult } = { current: null! };
 21	
 22	  const TestComponent = function () {
 23	    values.current = callback();
 24	
 25	    return null;
 26	  };
 27	
 28	  return {
 29	    rerender: () => {
 30	      act(() => {
 31	        render(createElement(TestComponent));
