 38	describe('useLinks', () => {
 39	  const mockData = {
 40	    accessGrants: [
 41	      {
 42	        metadata: { name: 'test-grant' },
 43	        status: { message: 'OK' }
 44	      }
 45	    ],
 46	    accessTokens: [
 47	      {
 48	        name: 'test-token',
 49	        status: { message: 'OK' }
 50	      }
 51	    ],
 52	    links: [
 53	      {
 54	        name: 'test-link'
 55	      }
 56	    ],
 57	    sites: [
 58	      {
 59	        remoteLinks: ['remote-site']
 60	      }
 61	    ]
 62	  };
 63	
 64	  beforeEach(() => {
 65	    vi.clearAllMocks();
 66	    mockUseWatchedSkupperResource
 67	      .mockReturnValueOnce({ data: mockData.accessGrants, loaded: true })
 68	      .mockReturnValueOnce({ data: mockData.accessTokens, loaded: true })
 69	      .mockReturnValueOnce({ data: mockData.links, loaded: true })
 70	      .mockReturnValueOnce({ data: mockData.sites, loaded: true });
 71	
 72	    global.URL.createObjectURL = mockCreateObjectURL;
 73	    mockCreateObjectURL.mockReturnValue('mock-url');
 74	  });
 75	
 76	  it('returns data and loading state', () => {
 77	    const { rerender, result } = renderHookTest(() => useLinks());
 78	    rerender();
 79	
 80	    expect(result().loading).toBe(false);
 81	    expect(result().data.accessGrants).toEqual(mockData.accessGrants);
 82	    expect(result().data.accessTokens).toEqual(mockData.accessTokens);
 83	    expect(result().data.links).toEqual(mockData.links);
 84	    expect(result().data.remoteLinks).toEqual([{ connectedTo: 'remote-site' }]);
 85	  });
 86	
 87	  it('handles delete link', async () => {
 88	    vi.mocked(RESTApi.deleteLink).mockResolvedValue();
 89	    vi.mocked(RESTApi.deleteAccessToken).mockResolvedValue();
 90	
 91	    const { rerender, result } = renderHookTest(() => useLinks());
 92	    rerender();
 93	
 94	    await act(async () => {
 95	      result().actions.handleDeleteLink('test-token');
 96	    });
 97	
 98	    expect(RESTApi.deleteAccessToken).toHaveBeenCalledWith('test-token');
 99	    expect(RESTApi.deleteLink).toHaveBeenCalledWith('test-token');
100	  });
101	
102	  it('handles download grant', () => {
103	    const mockLink = document.createElement('a');
104	    const mockClick = vi.fn();
105	    Object.defineProperty(mockLink, 'click', { value: mockClick });
106	
107	    const mockCreateElement = vi.spyOn(document, 'createElement');
108	    const mockAppendChild = vi.spyOn(document.body, 'appendChild');
109	    const mockRemoveChild = vi.spyOn(document.body, 'removeChild');
110	
111	    mockCreateElement.mockReturnValue(mockLink);
112	    mockAppendChild.mockImplementation(() => mockLink);
113	    mockRemoveChild.mockImplementation(() => mockLink);
114	
115	    const { rerender, result } = renderHookTest(() => useLinks());
116	    rerender();
117	
118	    act(() => result().actions.handleDownloadGrant(mockData.accessGrants[0] as AccessGrantCrdResponse));
119	
120	    expect(mockCreateElement).toHaveBeenCalledWith('a');
121	    expect(mockAppendChild).toHaveBeenCalled();
122	    expect(mockRemoveChild).toHaveBeenCalled();
123	    expect(mockClick).toHaveBeenCalled();
124	  });
125	
126	  it('handles delete link with partial name match', async () => {
127	    mockUseWatchedSkupperResource
128	      .mockReturnValueOnce({ data: mockData.accessGrants, loaded: true })
129	      .mockReturnValueOnce({
130	        data: [{ name: 'partial-token' }],
131	        loaded: true
132	      })
133	      .mockReturnValueOnce({ data: mockData.links, loaded: true })
134	      .mockReturnValueOnce({ data: mockData.sites, loaded: true });
135	
136	    vi.mocked(RESTApi.deleteLink).mockResolvedValue();
137	    vi.mocked(RESTApi.deleteAccessToken).mockResolvedValue();
138	
139	    const { rerender, result } = renderHookTest(() => useLinks());
140	    rerender();
141	
142	    await act(async () => {
143	      result().actions.handleDeleteLink('test-link-with-partial-token');
144	    });
145	
146	    expect(RESTApi.deleteLink).toHaveBeenCalledWith('test-link-with-partial-token');
147	  });
148	});

